ALTER TABLE public.invoice_templates
  ADD COLUMN IF NOT EXISTS whatsapp_template_rows JSONB DEFAULT '[{"category":"Marketing","price_per_message":"89.5-Paisa","template_type":"Include promotions or offers, informational updates, or invitation for customers to respond/take action. Any conversation that does not qualify as utility or authentication"},{"category":"Utility","price_per_message":"25-Paisa","template_type":"Facilitate a specific, agreed-upon request or transaction or update to a customer about an ongoing transaction, including post-purchase notifications and recurring billing"},{"category":"Authentication","price_per_message":"16-Paisa","template_type":"Enable businesses to authenticate users with one-time passcodes, potentially at multiple steps in the login process(e.g., account verification, account recovery, integrity challenges)"},{"category":"Service","price_per_message":"0-Paisa","template_type":"All user-initiated conversations will be categorized as service conversations, which help customers resolve enquiries."}]'::jsonb;

UPDATE public.invoice_templates
SET whatsapp_template_rows = '[{"category":"Marketing","price_per_message":"89.5-Paisa","template_type":"Include promotions or offers, informational updates, or invitation for customers to respond/take action. Any conversation that does not qualify as utility or authentication"},{"category":"Utility","price_per_message":"25-Paisa","template_type":"Facilitate a specific, agreed-upon request or transaction or update to a customer about an ongoing transaction, including post-purchase notifications and recurring billing"},{"category":"Authentication","price_per_message":"16-Paisa","template_type":"Enable businesses to authenticate users with one-time passcodes, potentially at multiple steps in the login process(e.g., account verification, account recovery, integrity challenges)"},{"category":"Service","price_per_message":"0-Paisa","template_type":"All user-initiated conversations will be categorized as service conversations, which help customers resolve enquiries."}]'::jsonb
WHERE whatsapp_template_rows IS NULL OR jsonb_typeof(whatsapp_template_rows) <> 'array';
